import React, { useState, useEffect } from 'react'
import Header from './components/Header'
import ProductList from './components/ProductList'
import Cart from './components/Cart'
import Checkout from './components/Checkout'
import Login from './components/Login'
import Register from './components/Register'
import AdminDashboard from './components/AdminDashboard'
import { authAPI } from './api'

function App(){
  const [page, setPage] = useState('products')
  const [authPage, setAuthPage] = useState(null) // 'login', 'register', or null
  const [user, setUser] = useState(null)
  const [token, setToken] = useState(localStorage.getItem('access_token'))
  const [cartTotal, setCartTotal] = useState(0)

  useEffect(()=>{
    if(token){
      authAPI.getProfile().then(res=>{
        setUser(res.data)
        // Route admin/owner users to dashboard
        if (res.data.role === 'admin' || res.data.role === 'owner') {
          setPage('admin')
        }
      }).catch(()=>{
        // Token might be invalid
        localStorage.removeItem('access_token')
        setToken(null)
      })
    }
  },[token])

  const handleLogout = () => {
    localStorage.removeItem('access_token')
    localStorage.removeItem('refresh_token')
    setToken(null)
    setUser(null)
    setAuthPage('login')
  }

  const handleLoginSuccess = () => {
    setToken(localStorage.getItem('access_token'))
    setAuthPage(null)
    setPage('products')
  }

  const handleRegisterSuccess = () => {
    setToken(localStorage.getItem('access_token'))
    setAuthPage(null)
    setPage('products')
  }

  // Show login/register pages if not authenticated
  if (!token) {
    if (authPage === 'register') {
      return <Register onSuccess={handleRegisterSuccess} onBack={() => setAuthPage('login')} />
    }
    return <Login onSuccess={handleLoginSuccess} onRegister={() => setAuthPage('register')} />
  }

  // Show admin dashboard for admin/owner users
  if (page === 'admin') {
    return <AdminDashboard user={user} onLogout={handleLogout} onBack={() => setPage('products')} />
  }

  return (
    <div className="min-h-screen bg-gray-100">
      <Header user={user} onLogout={handleLogout} onNavigate={(p)=>setPage(p)} />
      <main className="container mx-auto p-4">
        {page === 'products' && <ProductList onAddToCart={()=>setPage('cart')} />}
        {page === 'cart' && <Cart onCheckout={()=>setPage('checkout')} onBack={()=>setPage('products')} />}
        {page === 'checkout' && <Checkout onBack={()=>setPage('cart')} onSuccess={()=>setPage('products')} />}
      </main>
    </div>
  )
}

export default App
